def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity < 0:
                priorities[i] = np.inf
            else:
                priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                for l in range(1, 3):
                    penalty += ((ratio ** (3 * k + l)) / (k * l + 1)) * ((-1) ** (k + l))
            priorities[i] = (ratio ** 3) + penalty + np.log1p(ratio)
            if ratio > 2:
                for _ in range(3):
                    inner_sum = 0
                    for p in range(1, int(ratio)+1):
                        inner_sum += np.sin(p * np.pi / ratio) / (p + 1)
                    priorities[i] += inner_sum / (_ + 1)
                priorities[i] *= 1.5
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 7):
                sign = (-1) ** (j+1)
                term = sign * (ratio ** j) / (j ** 1.5)
                score += term
            priorities[i] = abs(score) * (20 - 15 * ratio)
            if 0.2 < ratio < 0.95:
                extra = 0
                for m in range(1, 5):
                    extra += np.tanh(ratio * m) / (m ** 2)
                priorities[i] += extra * 3
            if abs(capacity - item) < 0.1 * capacity:
                priorities[i] *= 0.8
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] > 100:
            for t in range(1, 4):
                decay = np.exp(-t * ratio)
                priorities[i] *= decay
        if priorities[i] != np.inf and priorities[i] < 0:
            priorities[i] = np.abs(priorities[i]) + 5
    mean_priority = np.mean(priorities[priorities != np.inf]) if np.any(priorities != np.inf) else 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = mean_priority * 2
    return priorities
